import { useEffect } from "react";
import ListItem from "../../components/People/ListItem";

const Pending = (props) => {
  useEffect(() => {
    const fetchData = async () => {
      const res = await fetch("", {
        headers: {
          Authorization: "Bearer " + props.token,
        },
      });
    };
  });
  return <div></div>;
};

export default Pending;
